1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Step {
8	  type: string;
9	  items: Item[];
10	}
11	
12	interface Scenario {
13	  customer: { years: number };
14	  steps: Step[];
15	}
16	
17	interface Result {
18	  premium: number;
19	}
20	
21	interface ScenarioOutput {
22	  results: Result[];
23	}
24	
25	const PROCESSING_FEE = 5;
26	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
27	const BUILDING_BLOCK_PREMIUM = 60;
28	const BUILDING_BLOCK_SIZE = 3;
29	const CURSED_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	
33	const BASE_PREMIUMS: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	  rune: 25,
39	};
40	
41	const groupItemsByType = (items: Item[]): Record<string, Item[]> => {
42	  const groups: Record<string, Item[]> = {};
43	  for (const item of items) {
44	    if (!groups[item.type]) {
45	      groups[item.type] = [];
46	    }
47	    groups[item.type].push(item);
48	  }
49	  return groups;
50	};
51	
52	const calculateItemsPremium = (items: Item[]): number => {
53	  const itemsByType = groupItemsByType(items);
54	  let total = 0;
55	
56	  for (const [type, typeItems] of Object.entries(itemsByType)) {
57	    if (typeItems.length === BUILDING_BLOCK_SIZE) {
58	      total += BUILDING_BLOCK_PREMIUM;
59	    } else {
60	      for (const item of typeItems) {
61	        let itemPremium = BASE_PREMIUMS[type];
62	        if (item.cursed) {
63	          itemPremium += BASE_PREMIUMS[type] * CURSED_SURCHARGE_RATE;
64	        }
65	        if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
66	          itemPremium += BASE_PREMIUMS[type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
67	        }
68	        total += itemPremium;
69	      }
70	    }
71	  }
72	
73	  return total;
74	};
75	
76	export function processScenario(scenario: Scenario): ScenarioOutput {
77	  const step = scenario.steps[0];
78	  const itemsPremium = calculateItemsPremium(step.items);
79	  const premium = itemsPremium + itemsPremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
80	  return { results: [{ premium }] };
81	}
